1	/**
2	 * Tests for backend/src/config/index.ts — requireSecret() behaviour.
3	 *
4	 * Each test manipulates process.env and calls vi.resetModules() so that the
5	 * config module is re-evaluated from scratch, exercising the four branches:
6	 *
7	 *   1. Secret is provided                           → value used directly
8	 *   2. Secret missing, production                   → throws (no opt-out)
9	 *   3. Secret missing, non-prod, no opt-in flag     → throws with helpful hint
10	 *   4. Secret missing, non-prod, ALLOW_INSECURE_DEV_SECRETS=true → fallback + warning
11	 */
12	
13	import { describe, it, expect, beforeEach, afterEach, vi } from 'vitest';
14	
15	// ─── Env snapshot ─────────────────────────────────────────────────────────────
16	// Capture the env state BEFORE any test mutations so we can fully restore it.
17	
18	const SNAPSHOT = { ...process.env };
19	
20	function restoreEnv() {
21	  // Remove keys added by tests
22	  for (const key of Object.keys(process.env)) {
23	    if (!(key in SNAPSHOT)) delete process.env[key];
24	  }
25	  // Restore original values (covers keys that were deleted or modified)
26	  Object.assign(process.env, SNAPSHOT);
27	}
28	
29	beforeEach(() => {
30	  vi.resetModules();
31	});
32	
33	afterEach(() => {
34	  restoreEnv();
35	  vi.resetModules();
36	});
37	
38	// ─── Helper to load a fresh config module ────────────────────────────────────
39	
40	async function loadConfig() {
41	  // Dynamic import after vi.resetModules() loads the module fresh each time.
42	  return import('@/config');
43	}
44	
45	// ─── Branch 1: secret is explicitly provided ─────────────────────────────────
46	
47	describe('config - secret provided via env var', () => {
48	  it('returns the provided JWT_SECRET value', async () => {
49	    process.env.JWT_SECRET = 'explicitly-set-jwt-secret';
50	    process.env.ENCRYPTION_KEY = 'explicitly-set-encryption-key';
51	    // ALLOW_INSECURE_DEV_SECRETS not needed when real values are present
52	    delete process.env.ALLOW_INSECURE_DEV_SECRETS;
53	
54	    const { config } = await loadConfig();
55	    expect(config.jwt.secret).toBe('explicitly-set-jwt-secret');
56	  });
57	
58	  it('returns the provided ENCRYPTION_KEY value', async () => {
59	    process.env.JWT_SECRET = 'any-jwt-secret';
60	    process.env.ENCRYPTION_KEY = 'explicitly-set-encryption-key';
61	    delete process.env.ALLOW_INSECURE_DEV_SECRETS;
62	
63	    const { config } = await loadConfig();
64	    expect(config.encryption.key).toBe('explicitly-set-encryption-key');
65	  });
66	
67	  it('uses the env var even when ALLOW_INSECURE_DEV_SECRETS is also set', async () => {
68	    process.env.JWT_SECRET = 'real-secret-value';
69	    process.env.ENCRYPTION_KEY = 'real-encryption-key';
70	    process.env.ALLOW_INSECURE_DEV_SECRETS = 'true';
71	
72	    const { config } = await loadConfig();
73	    expect(config.jwt.secret).toBe('real-secret-value');
74	  });
75	});
76	
77	// ─── Branch 2: secret missing in production ──────────────────────────────────
78	
79	describe('config - secret missing in production', () => {
80	  it('throws for JWT_SECRET when NODE_ENV=production', async () => {
81	    delete process.env.JWT_SECRET;
82	    process.env.ENCRYPTION_KEY = 'some-key';
83	    process.env.NODE_ENV = 'production';
84	    process.env.ALLOW_INSECURE_DEV_SECRETS = 'true'; // opt-in ignored in production
85	
86	    await expect(loadConfig()).rejects.toThrow('JWT_SECRET');
87	  });
88	
89	  it('throws for ENCRYPTION_KEY when NODE_ENV=production', async () => {
90	    process.env.JWT_SECRET = 'some-jwt';
91	    delete process.env.ENCRYPTION_KEY;
92	    process.env.NODE_ENV = 'production';
93	    process.env.ALLOW_INSECURE_DEV_SECRETS = 'true'; // opt-in ignored in production
94	
95	    await expect(loadConfig()).rejects.toThrow('ENCRYPTION_KEY');
96	  });
97	
98	  it('throws even when ALLOW_INSECURE_DEV_SECRETS=true in production', async () => {
99	    delete process.env.JWT_SECRET;
100	    process.env.ENCRYPTION_KEY = 'some-key';
101	    process.env.NODE_ENV = 'production';
102	    process.env.ALLOW_INSECURE_DEV_SECRETS = 'true';
103	
104	    await expect(loadConfig()).rejects.toThrow();
105	  });
106	});
107	
108	// ─── Branch 3: secret missing, non-prod, no opt-in ───────────────────────────
109	
110	describe('config - secret missing, no opt-in flag', () => {
111	  it('throws in development when JWT_SECRET is missing and flag is absent', async () => {
112	    delete process.env.JWT_SECRET;
113	    process.env.ENCRYPTION_KEY = 'some-key';
114	    process.env.NODE_ENV = 'development';
115	    delete process.env.ALLOW_INSECURE_DEV_SECRETS;
116	
117	    await expect(loadConfig()).rejects.toThrow('JWT_SECRET');
118	  });
119	
120	  it('throws in test when JWT_SECRET is missing and flag is absent', async () => {
121	    delete process.env.JWT_SECRET;
122	    process.env.ENCRYPTION_KEY = 'some-key';
123	    process.env.NODE_ENV = 'test';
124	    delete process.env.ALLOW_INSECURE_DEV_SECRETS;
125	
126	    await expect(loadConfig()).rejects.toThrow('JWT_SECRET');
127	  });
128	
129	  it('error message mentions ALLOW_INSECURE_DEV_SECRETS', async () => {
130	    delete process.env.JWT_SECRET;
131	    process.env.ENCRYPTION_KEY = 'some-key';
132	    process.env.NODE_ENV = 'development';
133	    delete process.env.ALLOW_INSECURE_DEV_SECRETS;
134	
135	    await expect(loadConfig()).rejects.toThrow('ALLOW_INSECURE_DEV_SECRETS');
136	  });
137	
138	  it('ALLOW_INSECURE_DEV_SECRETS=false is treated the same as absent', async () => {
139	    delete process.env.JWT_SECRET;
140	    process.env.ENCRYPTION_KEY = 'some-key';
141	    process.env.NODE_ENV = 'development';
142	    process.env.ALLOW_INSECURE_DEV_SECRETS = 'false';
143	
144	    await expect(loadConfig()).rejects.toThrow('JWT_SECRET');
145	  });
146	});
147	
148	// ─── Branch 4: secret missing, non-prod, with opt-in ─────────────────────────
149	
150	describe('config - secret missing with ALLOW_INSECURE_DEV_SECRETS=true', () => {
151	  it('returns dev-only fallback for JWT_SECRET in development', async () => {
152	    delete process.env.JWT_SECRET;
153	    process.env.ENCRYPTION_KEY = 'any-key';
154	    process.env.NODE_ENV = 'development';
155	    process.env.ALLOW_INSECURE_DEV_SECRETS = 'true';
156	
157	    const { config } = await loadConfig();
158	    expect(config.jwt.secret).toBe('dev-only-jwt-secret-not-for-production');
159	  });
160	
161	  it('returns dev-only fallback for ENCRYPTION_KEY in development', async () => {
162	    process.env.JWT_SECRET = 'any-jwt';
163	    delete process.env.ENCRYPTION_KEY;
164	    process.env.NODE_ENV = 'development';
165	    process.env.ALLOW_INSECURE_DEV_SECRETS = 'true';
166	
167	    const { config } = await loadConfig();
168	    expect(config.encryption.key).toBe('dev-only-encryption-key-not-for-production');
169	  });
170	
171	  it('emits a stderr warning when fallback is used', async () => {
172	    delete process.env.JWT_SECRET;
173	    process.env.ENCRYPTION_KEY = 'any-key';
174	    process.env.NODE_ENV = 'development';
175	    process.env.ALLOW_INSECURE_DEV_SECRETS = 'true';
176	
177	    const stderrSpy = vi.spyOn(process.stderr, 'write').mockImplementation(() => true);
178	    await loadConfig();
179	
180	    // Capture calls BEFORE mockRestore() — restore also clears mock.calls in vitest.
181	    const warnCalls = stderrSpy.mock.calls.map((c) => String(c[0]));
182	    stderrSpy.mockRestore();
183	    const jwtWarn = warnCalls.find((m) => m.includes('JWT_SECRET'));
184	    expect(jwtWarn).toBeDefined();
185	    expect(jwtWarn).toContain('insecure');
186	    expect(jwtWarn).toContain('ALLOW_INSECURE_DEV_SECRETS');
187	  });
188	
189	  it('works in test environment with the opt-in flag', async () => {
190	    delete process.env.JWT_SECRET;
191	    process.env.ENCRYPTION_KEY = 'any-key';
192	    process.env.NODE_ENV = 'test';
193	    process.env.ALLOW_INSECURE_DEV_SECRETS = 'true';
194	
195	    const { config } = await loadConfig();
196	    expect(config.jwt.secret).toBe('dev-only-jwt-secret-not-for-production');
197	  });
198	});
199	
200	// ─── requireSecret export ─────────────────────────────────────────────────────
201	
202	describe('requireSecret export', () => {
203	  it('is exported so it can be called by utilities that also need strict secret handling', async () => {
204	    process.env.JWT_SECRET = 'x';
205	    process.env.ENCRYPTION_KEY = 'y';
206	    const mod = await loadConfig();
207	    expect(typeof mod.requireSecret).toBe('function');
208	  });
209	});
