1	import express, { Request, Response } from 'express';
2	import cors from 'cors';
3	import path from 'path';
4	import { config } from './config';
5	import { logger } from './lib/logger';
6	import { requestLogger } from './middleware/requestLogger';
7	import { errorHandler } from './middleware/errorHandler';
8	import { startScheduler } from './lib/scheduler';
9	import { successResponse, errorResponse } from './types';
10	import { authenticate } from './middleware/auth';
11	
12	// Route imports
13	import authRoutes from './modules/auth/auth.routes';
14	import usersRoutes from './modules/users/users.routes';
15	import locationsRoutes from './modules/locations/locations.routes';
16	import inventoryRoutes from './modules/inventory/inventory.routes';
17	import reviewsRoutes from './modules/reviews/reviews.routes';
18	import trustRoutes from './modules/trust/trust.routes';
19	import moderationRoutes from './modules/moderation/moderation.routes';
20	import promotionsRoutes from './modules/promotions/promotions.routes';
21	import searchRoutes from './modules/search/search.routes';
22	import reportsRoutes from './modules/reports/reports.routes';
23	
24	const app = express();
25	
26	// Global middleware
27	app.use(cors());
28	app.use(express.json({ limit: '10mb' }));
29	app.use(express.urlencoded({ extended: true }));
30	app.use(requestLogger);
31	
32	// Health check
33	app.get('/api/health', (_req, res) => {
34	  res.json(successResponse({
35	    status: 'healthy',
36	    timestamp: new Date().toISOString(),
37	    version: '1.0.0',
38	    uptime: process.uptime(),
39	  }));
40	});
41	
42	// Authenticated file serving — requires a valid JWT; strips path to filename only to
43	// prevent directory traversal. Internal filesystem path is never reflected in errors.
44	app.get('/api/uploads/:filename', authenticate, (req: Request, res: Response) => {
45	  const filename = path.basename(req.params.filename as string);
46	  const filePath = path.resolve(config.upload.dir, filename);
47	  res.sendFile(filePath, (err) => {
48	    if (err && !res.headersSent) {
49	      res.status(404).json(errorResponse('NOT_FOUND', 'File not found'));
50	    }
51	  });
52	});
53	
54	// API routes
55	app.use('/api/auth', authRoutes);
56	app.use('/api/users', usersRoutes);
57	app.use('/api/locations', locationsRoutes);
58	app.use('/api/inventory', inventoryRoutes);
59	app.use('/api/reviews', reviewsRoutes);
60	app.use('/api/trust', trustRoutes);
61	app.use('/api/moderation', moderationRoutes);
62	app.use('/api/promotions', promotionsRoutes);
63	app.use('/api/search', searchRoutes);
64	app.use('/api/reports', reportsRoutes);
65	
66	// 404 handler
67	app.use((_req, res) => {
68	  res.status(404).json({ success: false, error: { code: 'NOT_FOUND', message: 'Route not found' } });
69	});
70	
71	// Global error handler
72	app.use(errorHandler);
73	
74	// Start server
75	app.listen(config.port, '0.0.0.0', () => {
76	  logger.info({ port: config.port, env: config.nodeEnv }, `HarborOps backend running on port ${config.port}`);
77	  startScheduler();
78	});
79	
80	export default app;
81	
