4	import { config } from '../../config';
5	import {
6	  CreateReviewInput,
7	  CreateFollowUpInput,
8	  CreateHostReplyInput,
9	  ReviewsQuery,
10	} from './reviews.schema';
11	
12	function businessError(code: string, message: string, statusCode: number): never {
13	  throw Object.assign(new Error(message), { statusCode, code });
14	}
15	
16	function calcOverall(cleanliness: number, communication: number, accuracy: number): number {
17	  return Math.round(((cleanliness + communication + accuracy) / 3) * 10) / 10;
18	}
19	
20	export class ReviewsService {
21	  async createReview(
22	    input: CreateReviewInput,
23	    reviewerId: number,
24	    files: Express.Multer.File[]
25	  ) {
26	    // Content filter
27	    if (input.text) {
28	      const { clean, flaggedWords } = await filterContent(input.text);
29	      if (!clean) {
30	        businessError('CONTENT_FILTERED', `Review contains prohibited words: ${flaggedWords.join(', ')}`, 422);
31	      }
32	    }
33	
34	    // Rate limit: max 3 reviews per hour
35	    const oneHourAgo = new Date(Date.now() - 60 * 60 * 1000);
36	    const recentCount = await prisma.rateLimitLog.count({
37	      where: { userId: reviewerId, action: 'create_review', createdAt: { gte: oneHourAgo } },
38	    });
39	    if (recentCount >= 3) {
40	      businessError('RATE_LIMITED', 'Maximum 3 reviews per hour', 429);
41	    }
42	
43	    // Cannot review yourself
44	    if (input.revieweeId && input.revieweeId === reviewerId) {
45	      businessError('SELF_REVIEW', 'Cannot review yourself', 422);
46	    }
47	
48	    // Validate tag IDs exist
49	    if (input.tagIds && input.tagIds.length > 0) {
50	      const tags = await prisma.tag.findMany({ where: { id: { in: input.tagIds } } });
51	      if (tags.length !== input.tagIds.length) {
52	        businessError('INVALID_TAGS', 'One or more tag IDs do not exist', 422);
53	      }
54	    }
55	
56	    const overallRating = calcOverall(
57	      input.ratingCleanliness,
58	      input.ratingCommunication,
59	      input.ratingAccuracy
60	    );
61	
62	    const review = await prisma.review.create({
63	      data: {
64	        reviewerId,
65	        revieweeId: input.revieweeId ?? null,
66	        targetType: input.targetType,
67	        targetId: input.targetId,
68	        ratingCleanliness: input.ratingCleanliness,
69	        ratingCommunication: input.ratingCommunication,
70	        ratingAccuracy: input.ratingAccuracy,
71	        overallRating,
72	        text: input.text ?? null,
73	        images: files.length > 0
74	          ? {
75	              create: files.map((f) => ({
76	                filePath: f.filename,
77	                fileSize: f.size,
78	              })),
79	            }
80	          : undefined,
81	        tags: input.tagIds && input.tagIds.length > 0
82	          ? { create: input.tagIds.map((tagId) => ({ tagId })) }
83	          : undefined,
84	      },
85	      include: {
86	        images: true,
87	        tags: { include: { tag: true } },
88	      },
89	    });
90	
91	    // Log for rate limiting
92	    await prisma.rateLimitLog.create({
93	      data: { userId: reviewerId, action: 'create_review' },
94	    });
95	
96	    logger.info({ reviewId: review.id, reviewerId }, 'Review created');
97	    return review;
98	  }
