5	/**
6	 * Preprocessor for tagIds: handles multipart form data where repeated fields
7	 * arrive as strings or string arrays instead of numbers.
8	 *
9	 * Accepted shapes → normalised result:
10	 *   undefined / null          → undefined  (field not sent)
11	 *   "5"  (single string)      → [5]        (one tag, no [] suffix)
12	 *   ["5", "3"]  (string[])    → [5, 3]     (multiple tags, repeated field)
13	 *   [5, 3]      (number[])    → [5, 3]     (JSON body, unchanged)
14	 */
15	function coerceTagIds(val: unknown): unknown {
16	  if (val === undefined || val === null) return undefined;
17	  const arr = Array.isArray(val) ? val : [val];
18	  return arr.map((v) => (typeof v === 'string' ? Number(v) : v));
19	}
20	
21	export const createReviewSchema = z.object({
22	  // z.coerce.number() accepts both JSON numbers and multipart string digits.
23	  revieweeId: z.coerce.number().int().positive().optional(),
24	  targetType: z.enum(['STAY', 'TASK']),
25	  targetId: z.coerce.number().int().positive(),
