28	  ratingAccuracy: z.coerce.number().int().min(1).max(5),
29	  text: z.string().max(5000).optional(),
30	  tagIds: z.preprocess(coerceTagIds, z.array(z.number().int().positive()).max(10).optional()),
31	});
